time_re = re.compile(r"\s*(\d{1,2})(?::(\d{2}))?\s*(am|pm)?\s*$", re.I)

def parse_time(t):
    if t is None:
        return None
    t = t.strip()
    # Normalize: ensure am/pm present if like '6' assume am? but safer: if endswith AM/PM ok else try to detect if contains digits+AM/PM
    m = time_re.match(t)
    if not m:
        return None
    h = int(m.group(1))
    minute = int(m.group(2)) if m.group(2) else 0
    ampm = m.group(3).lower() if m.group(3) else None
    if ampm == 'pm' and h != 12:
        h += 12
    if ampm == 'am' and h == 12:
        h = 0
    return h + minute/60.0

range_split_re = re.compile(r'[\-\u2013\u2014\u2012]')
weekdays = set(["Monday","Tuesday","Wednesday","Thursday","Friday"])

results = []
for b in businesses:
